var path = require('path');

module.exports = {
    hooks: {
        finish: function() {
            if (this.output.name !== 'website') return;

            var assetsRoot = path.join(__dirname, 'assets');
            var faviconPath = path.join(assetsRoot, 'favicon.ico');
            var appleTouchPath = path.join(assetsRoot, 'apple-touch-icon.png');

            return Promise.all([
                this.output.copyFile(faviconPath, 'gitbook/images/favicon.ico'),
                this.output.copyFile(faviconPath, 'favicon.ico'),
                this.output.copyFile(faviconPath, 'ru/gitbook/images/favicon.ico'),
                this.output.copyFile(faviconPath, 'en/gitbook/images/favicon.ico'),
                this.output.copyFile(appleTouchPath, 'ru/gitbook/images/apple-touch-icon-precomposed-152.png'),
                this.output.copyFile(appleTouchPath, 'en/gitbook/images/apple-touch-icon-precomposed-152.png'),
                this.output.copyFile(appleTouchPath, 'gitbook/images/apple-touch-icon-precomposed-152.png')
            ]);
        }
    },
    book: {
        assets: './assets',
        js: [
            'docs-header.js'
        ]
    }
};
